140	  const pathnameRef = useRef(pathname);
141	  const lastConfigIssuesSignatureRef = useRef<string | null>(null);
142	  const handledBootstrapThreadIdRef = useRef<string | null>(null);
143	
144	  pathnameRef.current = pathname;
