23	export default function BranchToolbar({
24	  threadId,
25	  onEnvModeChange,
26	  envLocked,
27	  onComposerFocusRequest,
28	}: BranchToolbarProps) {
29	  const threads = useStore((store) => store.threads);
30	  const projects = useStore((store) => store.projects);
31	  const setThreadBranchAction = useStore((store) => store.setThreadBranch);
32	  const draftThread = useComposerDraftStore((store) => store.getDraftThread(threadId));
33	  const setDraftThreadContext = useComposerDraftStore((store) => store.setDraftThreadContext);
34	
35	  const serverThread = threads.find((thread) => thread.id === threadId);
36	  const activeProjectId = serverThread?.projectId ?? draftThread?.projectId ?? null;
37	  const activeProject = projects.find((project) => project.id === activeProjectId);
38	  const activeThreadId = serverThread?.id ?? (draftThread ? threadId : undefined);
39	  const activeThreadBranch = serverThread?.branch ?? draftThread?.branch ?? null;
40	  const activeWorktreePath = serverThread?.worktreePath ?? draftThread?.worktreePath ?? null;
41	  const branchCwd = activeWorktreePath ?? activeProject?.cwd ?? null;
42	  const hasServerThread = serverThread !== undefined;
43	  const effectiveEnvMode = resolveEffectiveEnvMode({
44	    activeWorktreePath,
45	    hasServerThread,
46	    draftThreadEnvMode: draftThread?.envMode,
47	  });
48	
49	  const setThreadBranch = useCallback(
50	    (branch: string | null, worktreePath: string | null) => {
51	      if (!activeThreadId) return;
52	      const api = readNativeApi();
53	      // If the effective cwd is about to change, stop the running session so the
54	      // next message creates a new one with the correct cwd.
55	      if (serverThread?.session && worktreePath !== activeWorktreePath && api) {
56	        void api.orchestration
57	          .dispatchCommand({
58	            type: "thread.session.stop",
59	            commandId: newCommandId(),
60	            threadId: activeThreadId,
61	            createdAt: new Date().toISOString(),
62	          })
63	          .catch(() => undefined);
64	      }
65	      if (api && hasServerThread) {
66	        void api.orchestration.dispatchCommand({
67	          type: "thread.meta.update",
68	          commandId: newCommandId(),
69	          threadId: activeThreadId,
70	          branch,
71	          worktreePath,
72	        });
73	      }
74	      if (hasServerThread) {
75	        setThreadBranchAction(activeThreadId, branch, worktreePath);
76	        return;
77	      }
78	      const nextDraftEnvMode = resolveDraftEnvModeAfterBranchChange({
79	        nextWorktreePath: worktreePath,
80	        currentWorktreePath: activeWorktreePath,
81	        effectiveEnvMode,
82	      });
83	      setDraftThreadContext(threadId, {
84	        branch,
85	        worktreePath,
86	        envMode: nextDraftEnvMode,
87	      });
88	    },
89	    [
90	      activeThreadId,
91	      serverThread?.session,
92	      activeWorktreePath,
93	      hasServerThread,
94	      setThreadBranchAction,
95	      setDraftThreadContext,
96	      threadId,
97	      effectiveEnvMode,
98	    ],
99	  );
100	
101	  if (!activeThreadId || !activeProject) return null;
102	
103	  return (
104	    <div className="mx-auto flex w-full max-w-3xl items-center justify-between px-5 pb-3 pt-1">
105	      <div className="flex items-center gap-2">
106	        {envLocked || activeWorktreePath ? (
107	          <span className="border border-transparent px-[calc(--spacing(2)-1px)] text-sm font-medium text-muted-foreground/70 sm:text-xs">
108	            {activeWorktreePath ? "Worktree" : "Local"}
109	          </span>
110	        ) : (
111	          <Button
112	            type="button"
113	            variant="ghost"
114	            className="text-muted-foreground/70 hover:text-foreground/80"
115	            size="xs"
116	            onClick={() => onEnvModeChange(effectiveEnvMode === "local" ? "worktree" : "local")}
117	          >
118	            {effectiveEnvMode === "worktree" ? "New worktree" : "Local"}
119	          </Button>
120	        )}
121	      </div>
122	
123	      <BranchToolbarBranchSelector
124	        activeProjectCwd={activeProject.cwd}
125	        activeThreadBranch={activeThreadBranch}
126	        activeWorktreePath={activeWorktreePath}
127	        branchCwd={branchCwd}
128	        effectiveEnvMode={effectiveEnvMode}
129	        envLocked={envLocked}
130	        onSetThreadBranch={setThreadBranch}
131	        {...(onComposerFocusRequest ? { onComposerFocusRequest } : {})}
132	      />
133	    </div>
134	  );
135	}
