82	function formatRelativeTime(iso: string): string {
83	  const diff = Date.now() - new Date(iso).getTime();
84	  const minutes = Math.floor(diff / 60_000);
85	  if (minutes < 1) return "just now";
86	  if (minutes < 60) return `${minutes}m ago`;
87	  const hours = Math.floor(minutes / 60);
88	  if (hours < 24) return `${hours}h ago`;
89	  return `${Math.floor(hours / 24)}d ago`;
