      editor: "oklch(0.145 0 0)",
      terminal: "oklch(0.11 0 0)",
      statusBar: "oklch(0.12 0 0)",
    },
  },
  {
    id: "t3-light",
    name: "T3 Light",
    isDark: false,
    fontFamily: '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
    colors: {
      background: "#ffffff",
      foreground: "#262626",
      accent: "oklch(0.488 0.217 264)",
      sidebar: "#f5f5f5",
      editor: "#ffffff",
      terminal: "#fafafa",
      statusBar: "#e5e5e5",
    },
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    isDark: true,
    fontFamily: '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
    colors: {
      background: "#0d0f14",
      foreground: "#c9d1d9",
      accent: "oklch(0.65 0.18 220)",
      sidebar: "#090b0f",
      editor: "#0d0f14",
      terminal: "#080a0e",
      statusBar: "#060810",
    },
  },
] as const;

export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

export function getTheme(id: string): Theme {
  return BUILT_IN_THEMES.find((t) => t.id === id) ?? BUILT_IN_THEMES[0]!;
}

